// Filter only approved prospects (both company and persona approved)
const items = $input.all();

console.log('🎯 Filtering approved prospects...');
console.log('Total items received:', items.length);

const approved = items.filter(item => {
  const data = item.json;
  const companyApproved = data['Company Approved'] === 'Yes' || data.company_approved === true;
  const personaApproved = data['Persona Approved'] === 'Yes' || data.persona_approved === true;
  const hasEmail = data['Email Id'] || data.email;

  return companyApproved && personaApproved && hasEmail;
});

console.log('✅ Approved prospects:', approved.length);

if (approved.length === 0) {
  console.log('⚠️ No approved prospects found. Stopping workflow.');
  return [];
}

return approved.map(item => ({
  json: {
    // Person info
    person_name: item.json['Name'] || item.json.person_name,
    person_first_name: item.json.person_first_name || item.json['Name']?.split(' ')[0],
    person_title: item.json['Designation'] || item.json.person_title,
    person_department: item.json['Person Department'] || item.json.person_departments,
    person_seniority: item.json['Person Seniority'] || item.json.person_seniority,
    email: item.json['Email Id'] || item.json.email,
    linkedin_url: item.json['LinkedIn URL'] || item.json.person_linkedin_url,

    // Company info
    company_name: item.json['Company Name'] || item.json.company_name,
    company_domain: item.json['Company Domain'] || item.json.company_domain,
    company_industry: item.json['Company Industry'] || item.json.company_industry,
    company_employees: item.json['Employee Size'] || item.json.company_employees,
    company_location: item.json['Company Location'] || item.json.company_location,
    company_description: item.json['Company Description'] || item.json.company_description,

    // Tech context
    company_technologies: item.json['Company Technologies'] || item.json.company_technologies,
    company_keywords: item.json['Company Keywords'] || item.json.company_keywords
  }
}));

const item = $input.item.json;

// Get AI response
let aiResponse = item.text || item.output || '';
aiResponse = aiResponse.replace(/```json\n?|\n?```/g, '').trim();

let emailContent;
try {
  emailContent = JSON.parse(aiResponse);
} catch (e) {
  console.log('❌ Failed to parse email content');
  emailContent = {
    subject: 'API Development at ' + item.company_name,
    intro: 'Hi ' + item.person_first_name + ',',
    pain_point: 'Quick question about your API infrastructure.',
    cta: 'Worth a conversation?'
  };
}

// Get original prospect data
const prospectData = $('Filter Approved Prospects').item.json;

// Build complete email body
const emailBody = `${emailContent.intro}

${emailContent.pain_point}

${emailContent.cta}

Best,
[Your Name]
Postman`;

console.log('📧 Generated email for:', prospectData.person_name);
console.log('Subject:', emailContent.subject);

return {
  json: {
    // Prospect data
    firstName: prospectData.person_first_name,
    lastName: prospectData.person_name?.split(' ').slice(1).join(' ') || '',
    email: prospectData.email,
    companyName: prospectData.company_name,
    companyDomain: prospectData.company_domain,
    title: prospectData.person_title,
    linkedinUrl: prospectData.linkedin_url,

    // Email content - Instantly compatible variables
    subject: emailContent.subject,
    emailBody: emailBody,
    intro: emailContent.intro,
    painPoint: emailContent.pain_point,
    cta: emailContent.cta,

    // Context for personalization
    industry: prospectData.company_industry,
    techStack: prospectData.company_technologies,
    keywords: prospectData.company_keywords,
    companySize: prospectData.company_employees
  }
};

const item = $input.item.json;

// Get LinkedIn message from AI
const linkedinMessage = (item.text || item.output || '').trim();

// Get prospect data
const prospectData = $('Parse Email Output').item.json;

console.log('💼 Generated LinkedIn message for:', prospectData.firstName);
console.log('Message:', linkedinMessage.substring(0, 100));

return {
  json: {
    profileUrl: prospectData.linkedinUrl,
    message: linkedinMessage,
    firstName: prospectData.firstName,
    companyName: prospectData.companyName,
    title: prospectData.title
  }
};

const instantlyResult = $('Push to Instantly').item.json;
const aimfoxResult = $('Push to Aimfox').item.json;
const prospectData = $('Parse Email Output').item.json;

return {
  json: {
    timestamp: new Date().toISOString(),
    prospect_name: prospectData.firstName + ' ' + prospectData.lastName,
    email: prospectData.email,
    company: prospectData.companyName,
    title: prospectData.title,
    linkedin_url: prospectData.linkedinUrl,

    // Email campaign
    email_subject: prospectData.subject,
    email_sent: instantlyResult.success || true,
    instantly_status: instantlyResult.status || 'queued',

    // LinkedIn campaign  
    linkedin_message_sent: aimfoxResult.success || true,
    aimfox_status: aimfoxResult.status || 'queued',

    // Context
    tech_stack: prospectData.techStack,
    industry: prospectData.industry
  }
};
